const now = new Date();
const start = new Date(now.getFullYear(), now.getMonth(), now.getDate(), 0, 0, 0);
const end = new Date(now.getFullYear(), now.getMonth(), now.getDate(), 23, 59, 59);
return { timeMin: start.toISOString(), timeMax: end.toISOString(), today: now.toISOString().split('T')[0] };

const events = $.steps.listEvents.response.items || $.steps.listEvents.response.data || [];
const companyOverride = $.input.companyOverride || '';
const domains = new Set();
const attendeeList = [];
const meetings = [];

if (Array.isArray(events)) {
  events.forEach(e => {
    const attendees = (e.attendees || []).map(a => a.email).filter(Boolean);
    attendees.forEach(email => {
      const domain = email.split('@')[1];
      if (domain && domain.indexOf('gmail') < 0 && domain.indexOf('google') < 0 && domain.indexOf('outlook') < 0 && domain.indexOf('hotmail') < 0 && domain.indexOf('yahoo') < 0) {
        domains.add(domain);
      }
      attendeeList.push(email);
    });
    meetings.push({
      summary: e.summary || '(no title)',
      start: e.start ? (e.start.dateTime || e.start.date) : '',
      attendeeCount: attendees.length,
      attendeeEmails: attendees.slice(0, 5),
      location: e.location || ''
    });
  });
}

let searchQuery = companyOverride;
if (!searchQuery) {
  searchQuery = Array.from(domains).slice(0, 5).map(d => d.split('.')[0]).join(' OR ');
}
if (!searchQuery) searchQuery = 'recent business news';

return { meetings, domains: Array.from(domains), searchQuery, attendeeList, meetingCount: meetings.length };

const meetings = $.steps.extractCompanies.output.meetings;
const domains = $.steps.extractCompanies.output.domains;
const results = $.steps.searchCompanyNews.response.results || $.steps.searchCompanyNews.response.data || [];
const today = $.steps.getDateBounds.output.today;

let meetingData = 'TODAY\'S MEETINGS (' + today + '):\n\n';
meetings.forEach((m, i) => {
  const time = m.start ? new Date(m.start).toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' }) : 'TBD';
  meetingData += (i + 1) + '. ' + m.summary + ' at ' + time + '\n';
  if (m.location) meetingData += '   Location: ' + m.location + '\n';
  meetingData += '   Attendees: ' + m.attendeeCount + (m.attendeeEmails.length > 0 ? ' (' + m.attendeeEmails.join(', ') + ')' : '') + '\n\n';
});

let newsData = 'COMPANY/INDUSTRY NEWS:\n\n';
results.slice(0, 8).forEach((r, i) => {
  newsData += (i + 1) + '. ' + (r.title || 'N/A') + '\n';
  newsData += '   URL: ' + (r.url || '') + '\n';
  newsData += '   ' + (r.text || '').slice(0, 800) + '\n\n';
});

return { meetingData, newsData, today, meetingCount: meetings.length, domains, newsCount: results.length };

const d = $.steps.compileResearch.output;

let prompt = 'You are an executive assistant preparing pre-call research briefs. Create a comprehensive brief for today\'s meetings using the calendar data and company news below.\n\n';
prompt += d.meetingData + '\n';
prompt += d.newsData + '\n';
prompt += 'ATTENDEE DOMAINS: ' + (d.domains || []).join(', ') + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- For each meeting, identify relevant news about the companies/people involved\n';
prompt += '- Create talking points informed by recent news\n';
prompt += '- Suggest questions to ask based on company developments\n';
prompt += '- Note any potential concerns or opportunities from the news\n';
prompt += '- Prioritize meetings by importance/preparation needed\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "executiveSummary": "2-3 sentence overview of today",\n';
prompt += '  "meetingBriefs": [\n';
prompt += '    {\n';
prompt += '      "title": "meeting title",\n';
prompt += '      "time": "meeting time",\n';
prompt += '      "priority": "high|medium|low",\n';
prompt += '      "companyContext": "what to know about the company",\n';
prompt += '      "relevantNews": ["recent news item relevant to this meeting"],\n';
prompt += '      "talkingPoints": ["suggested talking point 1", "point 2"],\n';
prompt += '      "questionsToAsk": ["question based on recent news"],\n';
prompt += '      "prepActions": ["thing to prepare before meeting"]\n';
prompt += '    }\n';
prompt += '  ],\n';
prompt += '  "newsHighlights": ["key news item 1", "item 2"],\n';
prompt += '  "generalAdvice": "overarching advice for today"\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { executiveSummary: raw, meetingBriefs: [], newsHighlights: [], generalAdvice: '' }; }

const ai = $.steps.parseAI.output;
const today = $.steps.compileResearch.output.today;
const meetingCount = $.steps.compileResearch.output.meetingCount;

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Pre-Call Research Brief - ' + today, emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: (ai.executiveSummary || meetingCount + ' meeting(s) today.').slice(0, 1800) } });
blocks.push({ type: 'divider' });

if (ai.meetingBriefs && ai.meetingBriefs.length > 0) {
  ai.meetingBriefs.forEach((m, i) => {
    const priorityIcon = m.priority === 'high' ? ':red_circle:' : m.priority === 'medium' ? ':large_yellow_circle:' : ':white_circle:';
    let meetingText = priorityIcon + ' *' + (i + 1) + '. ' + (m.title || 'Meeting') + '*';
    if (m.time) meetingText += ' at ' + m.time;
    meetingText += '\n';

    if (m.companyContext) meetingText += '_Company:_ ' + m.companyContext + '\n';

    if (m.relevantNews && m.relevantNews.length > 0) {
      meetingText += '*Recent News:*\n';
      m.relevantNews.slice(0, 3).forEach(n => { meetingText += '  - ' + n + '\n'; });
    }

    if (m.talkingPoints && m.talkingPoints.length > 0) {
      meetingText += '*Talking Points:*\n';
      m.talkingPoints.forEach(tp => { meetingText += '  - ' + tp + '\n'; });
    }

    if (m.questionsToAsk && m.questionsToAsk.length > 0) {
      meetingText += '*Questions to Ask:*\n';
      m.questionsToAsk.forEach(q => { meetingText += '  - ' + q + '\n'; });
    }

    blocks.push({ type: 'section', text: { type: 'mrkdwn', text: meetingText.slice(0, 1800) } });
    if (i < ai.meetingBriefs.length - 1) blocks.push({ type: 'divider' });
  });
}

if (ai.newsHighlights && ai.newsHighlights.length > 0) {
  blocks.push({ type: 'divider' });
  let newsText = '*Key News Highlights:*\n';
  ai.newsHighlights.slice(0, 5).forEach((n, i) => { newsText += (i + 1) + '. ' + n + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: newsText.slice(0, 1800) } });
}

if (ai.generalAdvice) {
  blocks.push({ type: 'divider' });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*General Advice:* ' + ai.generalAdvice } });
}

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Google Calendar + Exa + Claude AI | One CLI' }] });

const fallbackText = 'Pre-Call Brief: ' + meetingCount + ' meetings analyzed with ' + (ai.newsHighlights || []).length + ' news highlights';
return { blocks, fallbackText };
